        fontSize: 13,
        fontWeight: '600',
        overflow: 'hidden',
        paddingHorizontal: 6,
        paddingVertical: 4,
    },
    lead: {
        color: '#71717a',
        fontSize: 20,
        lineHeight: 28,
    },
    large: {
        fontSize: 18,
        fontWeight: '600',
        lineHeight: 24,
    },
    small: {
        fontSize: 14,
        fontWeight: '500',
    },
    muted: {
        color: '#71717a',
        fontSize: 14,
        lineHeight: 20,
